/**
 * Clawzd — App Builder Panel.
 *
 * UI for browsing, creating, previewing, and managing mini-apps
 * generated by the LLM via the App Builder API.
 *
 * API:
 *   POST   /apps              — Create from template
 *   GET    /apps              — List all apps
 *   GET    /apps/{id}/meta    — App metadata
 *   GET    /apps/{id}/preview — Live preview
 *   PUT    /apps/{id}         — Update files
 *   DELETE /apps/{id}         — Delete
 *   GET    /apps/templates    — Available templates
 */

const AppBuilderPanel = (() => {
  let _apps = [];
  let _templates = {};

  function init() {
    // No overlay creation needed anymore
  }

  async function open() {
    await Promise.all([_loadApps(), _loadTemplates()]);
    _renderList();
  }

  function close() {
    // Left for compatibility, but no-op since it's inside SkillCatalog
  }

  async function _loadApps() {
    try {
      const res = await fetch('/apps');
      _apps = await res.json();
    } catch (e) {
      _apps = [];
    }
  }

  async function _loadTemplates() {
    try {
      const res = await fetch('/apps/templates');
      _templates = await res.json();
    } catch (e) {
      _templates = {};
    }
  }

  function _renderList() {
    const body = document.getElementById('ab-body');
    if (!body) return;

    if (_apps.length === 0) {
      body.innerHTML = `
        <div class="ab-empty">
          <div class="ab-empty-icon">🏗️</div>
          <p>No apps yet. Create your first mini-app!</p>
          <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.showCreate()">Create App</button>
        </div>
      `;
      return;
    }

    body.innerHTML = `
      <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px;">
        <h3 style="margin:0; font-size:16px;">🏗️ Your Apps</h3>
        <button class="ab-btn ab-btn-primary" onclick="AppBuilderPanel.showCreate()">Create App</button>
      </div>
      <div class="ab-grid">
        ${_apps.map(a => _renderAppCard(a)).join('')}
      </div>
    `;
  }

  function _renderAppCard(app) {
    const time = _timeAgo(app.updated_at || app.created_at);
    const fileCount = app.files ? app.files.length : 0;
    return `
      <div class="ab-card" data-id="${app.id}">
        <div class="ab-card-preview" onclick="AppBuilderPanel.preview('${app.id}')">
          <div class="ab-card-icon">🌐</div>
        </div>
        <div class="ab-card-body">
          <div class="ab-card-name">${app.name || 'Untitled'}</div>
          <div class="ab-card-meta">
            <span>v${app.version || 1}</span>
            <span>${fileCount} files</span>
            <span>${time}</span>
          </div>
        </div>
        <div class="ab-card-actions">
          <button class="ab-btn-sm" onclick="AppBuilderPanel.preview('${app.id}')" title="Preview">👁️</button>
          <button class="ab-btn-sm ab-btn-danger" onclick="AppBuilderPanel.remove('${app.id}')" title="Delete">🗑️</button>
        </div>
      </div>
    `;
  }

  function showCreate() {
    const body = document.getElementById('ab-body');
    if (!body) return;

    const templateOptions = Object.entries(_templates).map(([key, tpl]) =>
      `<div class="ab-template" onclick="AppBuilderPanel.create('${key}')">
        <div class="ab-template-icon">${key === 'dashboard' ? '📊' : '📄'}</div>
        <div class="ab-template-name">${tpl.name || key}</div>
        <div class="ab-template-desc">${tpl.description || ''}</div>
        <div class="ab-template-files">${(tpl.files || []).join(', ')}</div>
      </div>`
    ).join('');

    body.innerHTML = `
      <div class="ab-create">
        <button class="ab-btn-back" onclick="AppBuilderPanel.open()">← Back</button>
        <h4>Choose a template</h4>
        <input type="text" id="ab-app-name" class="ab-input" placeholder="App name..." value="My App">
        <div class="ab-templates-grid">${templateOptions}</div>
      </div>
    `;
  }

  async function create(templateKey) {
    const nameEl = document.getElementById('ab-app-name');
    const name = nameEl?.value || 'My App';

    try {
      const res = await fetch('/apps', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, template: templateKey }),
      });
      const app = await res.json();
      if (typeof window.toast === 'function') {
        window.toast(`App "${name}" created!`, 'success');
      }
      await _loadApps();
      _renderList();
      // Auto-open preview
      preview(app.id);
    } catch (e) {
      if (typeof window.toast === 'function') {
        window.toast('Failed to create app', 'error');
      }
    }
  }

  function preview(appId) {
    window.open(`/apps/${appId}/preview`, '_blank', 'width=800,height=600');
  }

  async function remove(appId) {
    if (!confirm('Delete this app?')) return;
    try {
      await fetch(`/apps/${appId}`, { method: 'DELETE' });
      await _loadApps();
      _renderList();
      if (typeof window.toast === 'function') {
        window.toast('App deleted', 'info');
      }
    } catch (e) {
      console.warn('Delete failed', e);
    }
  }

  function _timeAgo(iso) {
    if (!iso) return '';
    const d = (Date.now() - new Date(iso).getTime()) / 1000;
    if (d < 60) return 'just now';
    if (d < 3600) return Math.floor(d / 60) + 'm ago';
    if (d < 86400) return Math.floor(d / 3600) + 'h ago';
    return Math.floor(d / 86400) + 'd ago';
  }

  return { init, open, close, showCreate, create, preview, remove };
})();

window.AppBuilderPanel = AppBuilderPanel;
